import asyncio
import uuid
import json
from typing import AsyncIterator
from fastapi import FastAPI
from fastapi.responses import StreamingResponse
from langchain_anthropic import ChatAnthropic

app = FastAPI(title="ACP Research Agent")
llm = ChatAnthropic(model="claude-haiku-4-5-20251001")
runs: dict[str, dict] = {}


# ── Agent descriptor ──────────────────────────────────────────────────────
@app.get("/agents/research")
async def agent_descriptor():
    return {
        "agent_id": "research",
        "name": "Research Agent",
        "description": "Answers research questions using an LLM.",
        "metadata": {"version": "1.0"},
    }


# ── Non-streaming run ─────────────────────────────────────────────────────
@app.post("/runs")
async def create_run(body: dict):
    run_id = str(uuid.uuid4())
    # Extract text from first message part
    messages = body.get("messages", [])
    prompt = ""
    if messages:
        for part in messages[0].get("parts", []):
            if part.get("content_type") == "text/plain":
                prompt = part["content"]
                break

    try:
        response = await llm.ainvoke(prompt)
        run = {
            "run_id": run_id,
            "agent_id": body.get("agent_id", "research"),
            "status": "completed",
            "output": {
                "messages": [{
                    "role": "agent",
                    "parts": [{"content_type": "text/plain", "content": response.content}],
                }]
            },
        }
    except Exception as exc:
        run = {"run_id": run_id, "status": "failed", "error": {"message": str(exc)}}

    runs[run_id] = run
    return run


# ── Streaming run ─────────────────────────────────────────────────────────
@app.post("/runs/stream")
async def stream_run(body: dict):
    run_id = str(uuid.uuid4())
    messages = body.get("messages", [])
    prompt = ""
    if messages:
        for part in messages[0].get("parts", []):
            if part.get("content_type") == "text/plain":
                prompt = part["content"]
                break

    async def event_stream() -> AsyncIterator[str]:
        yield f"data: {json.dumps({'type': 'RunCreatedEvent', 'run_id': run_id, 'status': 'in_progress'})}\n\n"
        full_text = ""
        async for chunk in llm.astream(prompt):
            token = chunk.content
            full_text += token
            yield f"data: {json.dumps({'type': 'MessageOutputEvent', 'run_id': run_id, 'delta': token})}\n\n"
        yield f"data: {json.dumps({'type': 'RunCompletedEvent', 'run_id': run_id, 'status': 'completed', 'output': {'messages': [{'role': 'agent', 'parts': [{'content_type': 'text/plain', 'content': full_text}]}]}})}\n\n"

    return StreamingResponse(event_stream(), media_type="text/event-stream")


# ── Get run status ────────────────────────────────────────────────────────
@app.get("/runs/{run_id}")
async def get_run(run_id: str):
    return runs.get(run_id, {"error": "not found"})

import httpx
import json
from typing_extensions import TypedDict
from langgraph.graph import StateGraph, END


class ACPState(TypedDict):
    question: str
    agent_url: str
    answer: str
    run_id: str


def call_acp_streaming(state: ACPState) -> dict:
    """Submit an ACP run and collect the streamed answer."""
    payload = {
        "agent_id": "research",
        "messages": [{
            "role": "user",
            "parts": [{"content_type": "text/plain", "content": state["question"]}],
        }],
    }
    answer_parts = []
    run_id = ""

    with httpx.Client(timeout=60) as client:
        with client.stream("POST", f"{state['agent_url']}/runs/stream",
                           json=payload) as resp:
            for line in resp.iter_lines():
                if not line.startswith("data: "):
                    continue
                event = json.loads(line[6:])
                etype = event.get("type", "")
                if etype == "RunCreatedEvent":
                    run_id = event["run_id"]
                elif etype == "MessageOutputEvent":
                    answer_parts.append(event.get("delta", ""))
                elif etype == "RunCompletedEvent":
                    break

    return {"answer": "".join(answer_parts), "run_id": run_id}


builder = StateGraph(ACPState)
builder.add_node("call", call_acp_streaming)
builder.set_entry_point("call")
builder.add_edge("call", END)
graph = builder.compile()

out = graph.invoke({
    "question": "What is the ACP protocol?",
    "agent_url": "http://localhost:8000",
    "answer": "", "run_id": "",
})
print(out["answer"])

def handle_acp_with_hitl(base: str, question: str, human_fn) -> str:
    """Submit a run and handle awaiting_input pauses."""
    payload = {
        "agent_id": "research",
        "messages": [{"role": "user", "parts": [{"content_type": "text/plain", "content": question}]}],
    }
    answer = ""
    with httpx.Client(timeout=120) as client:
        with client.stream("POST", f"{base}/runs/stream", json=payload) as resp:
            run_id = None
            for line in resp.iter_lines():
                if not line.startswith("data: "):
                    continue
                event = json.loads(line[6:])
                etype = event.get("type", "")
                if etype == "RunCreatedEvent":
                    run_id = event["run_id"]
                elif etype == "MessageOutputEvent":
                    answer += event.get("delta", "")
                elif etype == "AwaitingInputEvent":
                    # surface question to human
                    prompt = event["message"]["parts"][0]["content"]
                    user_answer = human_fn(prompt)
                    # resume the run
                    client.post(f"{base}/runs/{run_id}/resume", json={
                        "messages": [{"role": "user",
                                      "parts": [{"content_type": "text/plain",
                                                 "content": user_answer}]}]
                    })
                elif etype == "RunCompletedEvent":
                    break
    return answer

import httpx


def acp_session_workflow(base: str, questions: list[str]) -> list[str]:
    """Run multiple questions in one ACP session (shared context)."""
    answers = []
    with httpx.Client(timeout=60) as client:
        # Create a session first
        session = client.post(f"{base}/sessions", json={"agent_id": "research"}).json()
        session_id = session["session_id"]

        for q in questions:
            run = client.post(f"{base}/runs", json={
                "agent_id": "research",
                "session_id": session_id,          # ties this Run to the session
                "messages": [{
                    "role": "user",
                    "parts": [{"content_type": "text/plain", "content": q}],
                }],
            }).json()

            # Extract answer from completed run output
            for msg in run.get("output", {}).get("messages", []):
                for part in msg.get("parts", []):
                    if part.get("content_type") == "text/plain":
                        answers.append(part["content"])

    return answers


# The agent sees all prior messages in the session automatically
results = acp_session_workflow(
    "http://localhost:8000",
    [
        "What is quantum computing?",
        "Give me three practical applications of what you just described.",  # refers back
    ]
)

import httpx
import asyncio


def safe_acp_call(base: str, question: str, timeout: float = 30) -> dict:
    """Submit a run with graceful timeout and cancellation."""
    payload = {
        "agent_id": "research",
        "messages": [{"role": "user", "parts": [{"content_type": "text/plain", "content": question}]}],
    }
    with httpx.Client(timeout=timeout) as client:
        # Submit
        run = client.post(f"{base}/runs", json=payload).json()
        run_id = run.get("run_id")
        status = run.get("status")

        if status == "completed":
            return {"ok": True, "run": run}
        if status == "failed":
            err = run.get("error", {})
            return {"ok": False, "code": err.get("code"), "message": err.get("message")}

        # Poll for in_progress runs (simplified; prefer SSE in production)
        for _ in range(60):
            import time; time.sleep(0.5)
            run = client.get(f"{base}/runs/{run_id}").json()
            if run["status"] == "completed":
                return {"ok": True, "run": run}
            if run["status"] == "failed":
                return {"ok": False, **run.get("error", {})}

        # Timed out — cancel the run
        client.post(f"{base}/runs/{run_id}/cancel")
        return {"ok": False, "code": "timeout", "message": f"Run {run_id} cancelled after timeout"}

from typing_extensions import TypedDict
from langgraph.graph import StateGraph, END
from langchain_anthropic import ChatAnthropic


class ResearchState(TypedDict):
    question: str
    answer: str


_llm = ChatAnthropic(model="claude-haiku-4-5-20251001")


def research_node(state: ResearchState) -> dict:
    resp = _llm.invoke(state["question"])
    return {"answer": resp.content}


_builder = StateGraph(ResearchState)
_builder.add_node("research", research_node)
_builder.set_entry_point("research")
_builder.add_edge("research", END)
research_graph = _builder.compile()


# ── ACP adapter ───────────────────────────────────────────────────────────
async def _run_acp_task(run_id: str, question: str):
    """Execute the LangGraph graph and update the ACP run record."""
    try:
        result = research_graph.invoke({"question": question, "answer": ""})
        runs[run_id].update({
            "status": "completed",
            "output": {
                "messages": [{
                    "role": "agent",
                    "parts": [{"content_type": "text/plain", "content": result["answer"]}],
                }]
            },
        })
    except Exception as exc:
        runs[run_id].update({
            "status": "failed",
            "error": {"code": "graph_error", "message": str(exc)},
        })
